#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int n;
        scanf("%d", &n);
        int chapters[n];
        for (int i = 0; i < n; i++) {
            scanf("%d", &chapters[i]);
        }
        int isTarantino = 0;
        for (int i = 0; i < n - 1; i++) {
            if (chapters[i] >= chapters[i + 1]) {
                isTarantino = 1;
                break;
            }
        }
        if (isTarantino) {
            printf("yes\n");
        } else {
            printf("no\n");
        }
    }
    return 0;
}

